import 'dart:io'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import '../../domain/repositories/user_profile_repository.dart'; import 'profile_controller_state.dart'; import 'profile_providers.dart';
class ProfileController extends StateNotifier<ProfileControllerState>{final Ref ref; ProfileController(this.ref):super(const ProfileControllerState()); UserProfileRepository get repo=>ref.read(userProfileRepositoryProvider); Future<void> updateProfile({required String displayName,required String city,required String township,required bool notificationEnabled}) async{final user=ref.read(currentUserProvider); if(user==null)return; state=state.copyWith(isLoading:true,errorMessage:null); try{await repo.updateProfile(userId:user.uid,displayName:displayName,city:city,township:township,notificationEnabled:notificationEnabled); ref.invalidate(currentUserProfileProvider); state=state.copyWith(isLoading:false,success:true);}catch(e){state=state.copyWith(isLoading:false,errorMessage:e.toString());}} Future<void> uploadAvatar(File image) async{final user=ref.read(currentUserProvider); if(user==null)return; final url=await repo.uploadProfilePhoto(userId:user.uid,image:image); await repo.updateProfilePhoto(userId:user.uid,photoUrl:url); ref.invalidate(currentUserProfileProvider);}}
